BEGIN;

ALTER TABLE sites DROP CONSTRAINT IF EXISTS sites_site_key_check;

ALTER TABLE sites ADD CONSTRAINT sites_site_key_check
  CHECK (
    site_key = ANY (ARRAY[
      'property'::text,
      'dentists'::text,
      'medical'::text,
      'solicitors'::text,
      'agency'::text,
      'generalist'::text,
      'contractors-ir35'::text,
      'construction-cis'::text,
      'charities'::text,
      'crypto'::text
    ])
  );

INSERT INTO sites (
  site_key, display_name, domain, gsc_property_url, bing_property_url,
  niche, target_buyer_persona, brand_voice_notes,
  content_dir, git_repo_path, blog_topics_table, active
) VALUES (
  'crypto',
  'Digital Asset Tax Partners',
  'www.digitalassettaxpartners.co.uk',
  'sc-domain:digitalassettaxpartners.co.uk',
  NULL,
  'UK specialist tax accountants for crypto investors, traders and businesses',
  'UK specialist tax accountants for crypto investors, traders and businesses',
  'plain-English specialist authority; UK English; no em-dashes',
  'crypto/web/content/blog',
  'crypto/web',
  'blog_topics',
  false
)
ON CONFLICT (site_key) DO NOTHING;

COMMIT;

